  1	import * as React from 'react';
  2	import { CEPH_BRAND_NAME } from '@odf/core/constants';
  3	import { ODF_MODEL_FLAG } from '@odf/core/features';
  4	import { useODFNamespaceSelector } from '@odf/core/redux';
  5	import { useGetExternalClusterDetails } from '@odf/core/redux/utils';
  6	import { getStorageClusterInNs } from '@odf/core/utils';
  7	import { ODF_OPERATOR, OCS_OPERATOR } from '@odf/shared/constants';
  8	import { useFetchCsv } from '@odf/shared/hooks/use-fetch-csv';
  9	import { SecretModel, StorageClusterModel } from '@odf/shared/models';
 10	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
 11	import { getName } from '@odf/shared/selectors';
 12	import {
 13	  SecretKind,
 14	  K8sResourceKind,
 15	  StorageClusterKind,
 16	} from '@odf/shared/types';
 17	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 18	import { getOprVersionFromCSV } from '@odf/shared/utils';
 19	import { referenceForModel } from '@odf/shared/utils';
 20	import { ExternalLink } from '@odf/shared/utils/link';
 21	import {
 22	  useFlag,
 23	  useK8sWatchResources,
 24	} from '@openshift-console/dynamic-plugin-sdk';
 25	import { Base64 } from 'js-base64';
 26	import {
 27	  Card,
 28	  CardBody,
 29	  CardHeader,
 30	  CardTitle,
 31	  DescriptionList,
 32	} from '@patternfly/react-core';
 33	import EncryptionPopover from '../common/details-card/encryption-popover';
 34	
 35	const getCephLink = (secret: SecretKind): string => {
 36	  const data = secret?.data?.userKey;
 37	  return data ? Base64.decode(data) : null;
 38	};
 39	
 40	type ResourcesObject = {
 41	  [key: string]: {
 42	    data: K8sResourceKind | K8sResourceKind[];
 43	    loaded: boolean;
 44	    loadError: any;
 45	  };
 46	};
 47	
 48	const k8sResources = (clusterNs: string) => ({
 49	  ocs: {
 50	    kind: referenceForModel(StorageClusterModel),
 51	    isList: true,
 52	  },
 53	  secret: {
 54	    kind: SecretModel.kind,
 55	    namespace: clusterNs,
 56	    name: 'rook-ceph-dashboard-link',
 57	  },
 58	});
 59	
 60	export const DetailsCard: React.FC = () => {
 61	  const { t } = useCustomTranslation();
 62	  const isODF = useFlag(ODF_MODEL_FLAG);
 63	
 64	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
 65	  const { clusterNamespace: clusterNs } = useGetExternalClusterDetails();
 66	
 67	  const resourcesObj: ResourcesObject = useK8sWatchResources(
 68	    k8sResources(clusterNs)
 69	  );
 70	  const ocsCluster = getStorageClusterInNs(
 71	    resourcesObj['ocs'].data as StorageClusterKind[],
 72	    clusterNs
 73	  );
 74	
 75	  const ocsName = getName(ocsCluster);
 76	
 77	  const [csv, csvLoaded, csvError] = useFetchCsv({
 78	    specName: !isODF ? OCS_OPERATOR : ODF_OPERATOR,
 79	    namespace: odfNamespace,
 80	    startPollingInstantly: isNsSafe,
 81	  });
 82	
 83	  const subscriptionVersion = getOprVersionFromCSV(csv);
 84	
 85	  const serviceName = isODF
 86	    ? t('Data Foundation')
 87	    : t('OpenShift Container Storage');
 88	  const cephLink = getCephLink(resourcesObj['secret'].data as K8sResourceKind);
 89	
 90	  return (
 91	    <Card>
 92	      <CardHeader>
 93	        <CardTitle>{t('Details')}</CardTitle>
 94	      </CardHeader>
 95	      <CardBody>
 96	        <DescriptionList>
 97	          <DetailItem title={t('Service name')}>{serviceName}</DetailItem>
 98	          <DetailItem
 99	            title={t('Cluster name')}
100	            error={resourcesObj['ocs'].loadError}
101	            isLoading={!resourcesObj['ocs'].loaded}
102	            data-test-id="cluster-name"
103	          >
104	            {ocsName}
105	          </DetailItem>
106	          <DetailItem
107	            title={t('Provider')}
108	            isLoading={
109	              !resourcesObj['secret'].loaded &&
110	              !resourcesObj['secret'].loadError
111	            }
112	          >
113	            {cephLink ? (
114	              <ExternalLink href={cephLink} text={CEPH_BRAND_NAME} />
115	            ) : (
116	              CEPH_BRAND_NAME
117	            )}
118	          </DetailItem>
119	          <DetailItem title={t('Mode')}>External</DetailItem>
120	          <DetailItem
121	            title={t('Version')}
122	            isLoading={!csvLoaded}
123	            error={csvError}
124	            data-test-id="cluster-subscription"
125	          >
126	            {subscriptionVersion}
127	          </DetailItem>
128	          <DetailItem
129	            key="encryption"
130	            title={t('Encryption')}
131	            isLoading={!resourcesObj['ocs'].loaded}
132	            error={resourcesObj['ocs'].loadError}
133	          >
134	            <EncryptionPopover cluster={ocsCluster} isObjectDashboard={false} />
135	          </DetailItem>
136	        </DescriptionList>
137	      </CardBody>
138	    </Card>
139	  );
140	};
141	
142	export default DetailsCard;

